import{_ as e,H as l,f as a,i as r}from"./chunks/framework.eFU6Tutu.js";const x=JSON.parse('{"title":"Микрозелень","description":"","frontmatter":{},"headers":[],"relativePath":"plants/microgreens.md","filePath":"plants/microgreens.md"}'),i={name:"plants/microgreens.md"};function n(s,t,d,o,h,f){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="микрозелень" tabindex="-1">Микрозелень <a class="header-anchor" href="#микрозелень" aria-label="Permalink to &quot;Микрозелень&quot;">​</a></h1><p>Микрозелень — это молодые побеги растений в фазе первых семядольных или 1-2 настоящих листьев, высотой до 5-10 см. Она невероятно популярна среди сторонников здорового питания благодаря высокой концентрации витаминов и яркому вкусу. Вырастить её на подоконнике очень просто и быстро.</p><h2 id="описание" tabindex="-1">Описание <a class="header-anchor" href="#описание" aria-label="Permalink to &quot;Описание&quot;">​</a></h2><p>Микрозелень — это не конкретный сорт, а стадия развития растения. В пищу употребляют стебелёк и семядольные листья, срезая их над поверхностью грунта. В отличие от проростков (которые едят целиком вместе с корнем и семенем), микрозелень срезают, и корни не используют. Культуры для микрозелени бывают самыми разными: от классических пряных трав до овощей и злаков.</p><h2 id="популярные-культуры-для-дома" tabindex="-1">Популярные культуры для дома <a class="header-anchor" href="#популярные-культуры-для-дома" aria-label="Permalink to &quot;Популярные культуры для дома&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Культура</th><th style="text-align:left;">Вкус и особенности</th><th style="text-align:left;">Средний срок до сбора</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Редис</strong></td><td style="text-align:left;">Острый, пряный, сочный. Очень неприхотлив</td><td style="text-align:left;">5-7 дней</td></tr><tr><td style="text-align:left;"><strong>Брокколи</strong></td><td style="text-align:left;">Нежный, слегка капустный</td><td style="text-align:left;">6-10 дней</td></tr><tr><td style="text-align:left;"><strong>Горчица</strong></td><td style="text-align:left;">Пикантный, горчичный</td><td style="text-align:left;">6-8 дней</td></tr><tr><td style="text-align:left;"><strong>Кресс-салат</strong></td><td style="text-align:left;">Острый, с горчинкой</td><td style="text-align:left;">7-10 дней</td></tr><tr><td style="text-align:left;"><strong>Подсолнечник</strong></td><td style="text-align:left;">Ореховый, сладковатый, хрустящий</td><td style="text-align:left;">8-12 дней</td></tr><tr><td style="text-align:left;"><strong>Горошек</strong></td><td style="text-align:left;">Сочный, сладковатый, с хрустом</td><td style="text-align:left;">10-14 дней</td></tr><tr><td style="text-align:left;"><strong>Базилик</strong></td><td style="text-align:left;">Классический аромат</td><td style="text-align:left;">10-15 дней</td></tr><tr><td style="text-align:left;"><strong>Свёкла</strong></td><td style="text-align:left;">Сладковатый, яркий</td><td style="text-align:left;">10-14 дней</td></tr></tbody></table><h2 id="уход" tabindex="-1">Уход <a class="header-anchor" href="#уход" aria-label="Permalink to &quot;Уход&quot;">​</a></h2><p>Выращивание микрозелени — особый, сверхбыстрый процесс, но общие принципы схожи с уходом за другой зеленью. Подробнее читайте в <a href="/care/greens/#микрозелень">гайде по уходу за зеленью</a>.</p><h2 id="как-использовать-в-еде" tabindex="-1">Как использовать в еде <a class="header-anchor" href="#как-использовать-в-еде" aria-label="Permalink to &quot;Как использовать в еде&quot;">​</a></h2><p><a href="/recipes/microgreens.html">Рецепты с зеленью</a></p><ul><li>Украшение супов, салатов, основных блюд</li><li>Добавка в сэндвичи и бургеры</li><li>Ингредиент для смузи и зелёных коктейлей</li><li>База для микрозелени-салатов</li><li>Начинка для омлетов</li></ul><h2 id="полезные-своиства" tabindex="-1">Полезные свойства <a class="header-anchor" href="#полезные-своиства" aria-label="Permalink to &quot;Полезные свойства&quot;">​</a></h2><ul><li>Концентрация витаминов (С, А, К, Е, группы В) в 4-6 раз выше, чем во взрослых растениях</li><li>Содержит антиоксиданты и хлорофилл</li><li>Богата железом, цинком, магнием и калием</li><li>Легко усваивается организмом</li><li>Укрепляет иммунитет и повышает энергию</li></ul><h2 id="источники-информации" tabindex="-1">Источники информации <a class="header-anchor" href="#источники-информации" aria-label="Permalink to &quot;Источники информации&quot;">​</a></h2><ul><li><a href="https://azbyka.ru/garden/kak-vyrastit-mikrozelen-na-podokonnike/" target="_blank" rel="noreferrer">Азбука садовода — Как вырастить микрозелень на подоконнике</a></li><li><a href="https://lenta.ru/articles/2024/12/25/kak-vyrastit-mikrozelen-v-domashnih-usloviyah/" target="_blank" rel="noreferrer">Лента.ру — Как вырастить микрозелень в домашних условиях</a></li></ul><h2 id="похожие-растения" tabindex="-1">Похожие растения <a class="header-anchor" href="#похожие-растения" aria-label="Permalink to &quot;Похожие растения&quot;">​</a></h2><ul><li><a href="/plants/chives.html">Лук (зелёный)</a></li><li><a href="/plants/salad.html">Салаты</a></li><li><a href="/plants/basil.html">Базилик</a></li></ul>',17)])])}const c=e(i,[["render",n]]);export{x as __pageData,c as default};
